1	<!DOCTYPE html>
2	<html>
3	<head>
4	<meta charset="UTF-8">
5	<title>HTML5 コメントジェネレーター</title>
6	<!-- ver 0.0.8 -->
7	<script src="https://code.createjs.com/createjs-2015.11.26.min.js"></script>
8	<script type="text/javascript" src="http://ajax.googleapis.com/ajax/libs/jquery/1.11.0/jquery.min.js"></script>
9	<script src="CommentGenerator.js"></script>
10	
11	<script>
12	//outlineが壊れるのを少しマシにする
13	//参考：https://github.com/HAKASHUN/manabi/issues/86
14	createjs.Text.prototype.draw = function(ctx, ignoreCache) {
15		if (this.DisplayObject_draw(ctx, ignoreCache)) {
16			return true;
17		}
18	
19		var col = this.color || "#000";
20		if (this.outline) {
21			ctx.strokeStyle = col;
22			ctx.lineWidth = this.outline * 1;
23	
24			ctx.miterLimit = 2;
25			ctx.lineJoin = 'circle';
26		} else {
27			ctx.fillStyle = col;
28		}
29	
30		this._drawText(this._prepContext(ctx));
31		return true;
32	};
33	
34	function init() {
35		var HcgFormat = {};
36		var TxtFormat = new Object();
37		/************************************************/
38		createjs.Ticker.setFPS(30);
39		HcgFormat.CommentMax = 3;	//コメントの最大表示数 ここを4以上にしたらcanvasのheight値も変えること
40		HcgFormat.SkinHeight = 32;	//使用するスキンの高さ
41		var DemoMode  		 = 0;	//デモモード
42		/************************************************/
43		var stage = new createjs.Stage("canvas");
44		var obj = [];
45		var startTime = Math.floor(new Date().getTime()/1000);
46		var startNo   = -1;
47		var CommentNow = 0;
48		var SettingLoaded = false;
49		var FullPath = location.href;
50		var PathArray = FullPath.split('/');
51		var PathHead = "";
52		if(PathArray[2] == "absolute") {
53			PathHead = "http://absolute/";
54		} else {
55			PathHead = "";
56		}
57		HcgFormat.PathHead = PathHead;
58		var CurrentPath = "";
59		for(var i=0; i<PathArray.length-1; i++){
60			CurrentPath += PathArray[i] + "/";
61		}
62		HcgFormat.CurrentPath = CurrentPath;
63		
64		createjs.Ticker.addEventListener('tick', mainLoop);
65		function mainLoop() {
66			stage.update();
67		}
68		
69		SettingFunc();
70		var SettingTimer = setInterval(SettingFunc, 5000);
71		if(DemoMode) {
72			console.log("デモモード");
73			var DemoTimer = setInterval(DemoFunc, 5000);
74		} else {
75			console.log("HTML5コメントジェネレーター");
76			var CommentTimer = setInterval(CommentFunc, 500);
77		}
78		
79		//コメント(XML)を読んでコメントジェネレーターに渡す
80		function CommentFunc() {
81			if(SettingLoaded) {
82				//XML読み込み
83				$(function(){
84					parse();
85					$("#select_game").change(function() {
86						var result = $(this).val();
87						parse(result);
88					});
89				});
90				function parse(type) {
91					$.ajax({
92						url: 'comment.xml',
93						type: 'GET',
94						dataType: 'xml',
95						timeout: 5000,
96						success:function(xml) {
97							xml = xml.getElementsByTagName('comment');
98							for(var i=0; i<xml.length; i++) {
99								if((startTime < xml[i].getAttributeNode("time").value) ||
100								((startTime == xml[i].getAttributeNode("time").value) && (startNo < xml[i].getAttributeNode("no").value))) {
101									startTime = xml[i].getAttributeNode("time").value;
102									startNo   = xml[i].getAttributeNode("no").value;
103									var SlashComment = TxtFormat['SlashCommentVisible'];
104									var BSPComment = TxtFormat['BSPCommentVisible'];
105									var OwnerComment = TxtFormat['OwnerCommentVisible'];
106									if(isComment(xml[i].firstChild.nodeValue, SlashComment, BSPComment)) {
107										if(OwnerComment==1 || ((OwnerComment==0)&&(xml[i].getAttributeNode("owner").value!=1))) {
108											var handle="";
109											if(xml[i].getAttributeNode("handle") != null) {
110												handle = xml[i].getAttributeNode("handle").value;
111											} else {
112												if(xml[i].getAttributeNode("no") != null) {
113													if(TxtFormat['NoHandleType']==0) {
114														handle = xml[i].getAttributeNode("no").value+"コメ";
115													} else if(TxtFormat['NoHandleType']==1) {
116														handle = TxtFormat['NoHandleName'];
117													}
118												}
119											}
120											console.log(xml[i].firstChild.nodeValue);
121											var CGen = new CommentGenerator(handle, fixComment(xml[i].firstChild.nodeValue), HcgFormat, TxtFormat);
122											obj[CommentNow] = CGen;
123											obj[CommentNow].y = HcgFormat['SkinHeight']*(HcgFormat['CommentMax']-1);
124											stage.addChild(obj[CommentNow].getSkinImage());
125											stage.addChild(obj[CommentNow].getBGColorBar());
126											stage.addChild(obj[CommentNow].getEdgeCommentText());
127											stage.addChild(obj[CommentNow].getCommentText());
128											for(var i=CommentNow; i>(CommentNow-(HcgFormat['CommentMax']-1)); i--) {
129												if((i-1)>=0) {
130													obj[(i-1)].getSkinImage().y -= HcgFormat['SkinHeight'];
131													obj[(i-1)].getBGColorBar().y -= HcgFormat['SkinHeight'];
132													obj[(i-1)].getEdgeCommentText().y -= HcgFormat['SkinHeight'];
133													obj[(i-1)].getCommentText().y -= HcgFormat['SkinHeight'];
134												}
135											}
136									
137											if((CommentNow-HcgFormat['CommentMax'])>=0) {
138												stage.removeChild(obj[(CommentNow-HcgFormat['CommentMax'])].getSkinImage());
139												stage.removeChild(obj[(CommentNow-HcgFormat['CommentMax'])].getBGColorBar());
140												stage.removeChild(obj[(CommentNow-HcgFormat['CommentMax'])].getEdgeCommentText());
141												stage.removeChild(obj[(CommentNow-HcgFormat['CommentMax'])].getCommentText());
142												delete obj[(CommentNow-HcgFormat['CommentMax'])];
143											}
144											CommentNow++;
145										}
146									}
147									break;
148								}
149							}
150						},
151						error:function() {
152							alert("ロード失敗");
153						}
154					});
155				}
156			}
157		}
158		
159		function SettingFunc() {
160			//XML読み込み
161			$(function(){
162				parse();
163				
164				$("#select_game").change(function() {
165					var result = $(this).val();
166					parse(result);
167				});
168			});
169			function parse(type) {
170				$.ajax({
171					url: 'setting.xml',
172					type: 'GET',
173					dataType: 'xml',
174					timeout: 5000,
175					success:function(xml) {
176						var skinfile = "";
177						var skinfolder = "";
178						if(xml.getElementsByTagName('SkinFile')[0].firstChild != null) {
179							skinfile = xml.getElementsByTagName('SkinFile')[0].firstChild.nodeValue;
180						}
181						if(xml.getElementsByTagName('SkinFolder')[0].firstChild != null) {
182							skinfolder = xml.getElementsByTagName('SkinFolder')[0].firstChild.nodeValue;
183						}
184						var txtFormat = {
185							'HandleVisible' : xml.getElementsByTagName('HandleVisible')[0].firstChild.nodeValue,
186							'HandleOrder' : xml.getElementsByTagName('HandleOrder')[0].firstChild.nodeValue,
187							'Honorific' : xml.getElementsByTagName('Honorific')[0].firstChild.nodeValue,
188							'NoHandleType' : xml.getElementsByTagName('NoHandleType')[0].firstChild.nodeValue,
189							'NoHandleName' : xml.getElementsByTagName('NoHandleName')[0].firstChild.nodeValue,
190							'TxtColor' : xml.getElementsByTagName('TxtColor')[0].firstChild.nodeValue,
191							'TxtFont' : xml.getElementsByTagName('TxtFont')[0].firstChild.nodeValue,
192							'TxtSize' : xml.getElementsByTagName('TxtSize')[0].firstChild.nodeValue,
193							'BgColor' : xml.getElementsByTagName('BgColor')[0].firstChild.nodeValue,
194							'BgColorType' : xml.getElementsByTagName('BgColorType')[0].firstChild.nodeValue,
195							'TxtEdgeColor' : xml.getElementsByTagName('TxtEdgeColor')[0].firstChild.nodeValue,
196							'TxtEdgeType' : xml.getElementsByTagName('TxtEdgeType')[0].firstChild.nodeValue,
197							'TxtEdgeValue' : xml.getElementsByTagName('TxtEdgeValue')[0].firstChild.nodeValue,
198							'SkinType' : xml.getElementsByTagName('SkinType')[0].firstChild.nodeValue,
199							'SkinFile' : skinfile,
200							'SkinFolder' : skinfolder,
201							'TimeType' : xml.getElementsByTagName('TimeType')[0].firstChild.nodeValue,
202							'TimeValue' : xml.getElementsByTagName('TimeValue')[0].firstChild.nodeValue,
203							'TxtUpSpace' : xml.getElementsByTagName('TxtUpSpace')[0].firstChild.nodeValue,
204							'TxtLeftSpace' : xml.getElementsByTagName('TxtLeftSpace')[0].firstChild.nodeValue,
205							'TxtLength' : xml.getElementsByTagName('TxtLength')[0].firstChild.nodeValue,
206							'TxtLengthValue' : xml.getElementsByTagName('TxtLengthValue')[0].firstChild.nodeValue,
207							'OwnerCommentVisible' : xml.getElementsByTagName('OwnerCommentVisible')[0].firstChild.nodeValue,
208							'SlashCommentVisible' : xml.getElementsByTagName('SlashCommentVisible')[0].firstChild.nodeValue,
209							'BSPCommentVisible' : xml.getElementsByTagName('BSPCommentVisible')[0].firstChild.nodeValue,
210							'Direction' : xml.getElementsByTagName('Direction')[0].firstChild.nodeValue,
211							'userBGColor' : xml.getElementsByTagName('userBGColor')[0].firstChild.nodeValue,
212							'userSkinName' : xml.getElementsByTagName('userSkinName')[0].firstChild.nodeValue
213						};
214						setTxtFormat(txtFormat);
215					},
216					error:function() {
217						alert("ロード失敗");
218					}
219				});
220			}
221		}
222		
223		//デモ
224		function DemoFunc(){
225			if(SettingLoaded) {
226				var CGen = new CommentGenerator("コテハン", "コメント", HcgFormat, TxtFormat);
227				obj[CommentNow] = CGen;
228				stage.addChild(obj[CommentNow].getSkinImage());
229				stage.addChild(obj[CommentNow].getBGColorBar());
230				stage.addChild(obj[CommentNow].getEdgeCommentText());
231				stage.addChild(obj[CommentNow].getCommentText());
232				for(var i=CommentNow; i>(CommentNow-(HcgFormat['CommentMax']-1)); i--) {
233					if((i-1)>=0) {
234						obj[(i-1)].getSkinImage().y -= HcgFormat['SkinHeight'];
235						obj[(i-1)].getBGColorBar().y -= HcgFormat['SkinHeight'];
236						obj[(i-1)].getEdgeCommentText().y -= HcgFormat['SkinHeight'];
237						obj[(i-1)].getCommentText().y -= HcgFormat['SkinHeight'];
238					}
239				}
240			
241				if((CommentNow-HcgFormat['CommentMax'])>=0) {
242					stage.removeChild(obj[(CommentNow-HcgFormat['CommentMax'])].getSkinImage());
243					stage.removeChild(obj[(CommentNow-HcgFormat['CommentMax'])].getBGColorBar());
244					stage.removeChild(obj[(CommentNow-HcgFormat['CommentMax'])].getEdgeCommentText());
245					stage.removeChild(obj[(CommentNow-HcgFormat['CommentMax'])].getCommentText());
246					delete obj[(CommentNow-HcgFormat['CommentMax'])];
247				}
248				CommentNow++;
249			}
250		}
251		
252		function setTxtFormat(txtFormat) {
253			console.log("設定を読み込みました");
254			TxtFormat = txtFormat;
255			SettingLoaded = true;
256		}
257		
258		//コメントとして処理するかどうかの判断
259		function isComment(comment, Slash, BSP) {
260			if(comment.substring(0,11)=="/press show") {
261				//ニコ生のBSP
262				if(BSP==1) {
263					return true;
264				} else {
265					return false;
266				}
267			} else if(comment.substring(0,1)=="/") {
268				// "/"から始まるコメント
269				if(Slash==1) {
270					return true;
271				} else {
272					return false;
273				}
274			}
275			return true;
276		}
277		
278		//コメント処理
279		function fixComment(comment) {
280			if(comment.substring(0,11)=="/press show") {
281				//BSPコメント
282				var bsp_array = comment.split(" ");
283				var bsp = "";
284				for(var i=3; i<bsp_array.length; i++) {
285					bsp += bsp_array[i]+ " ";
286				}
287				comment = bsp;
288			} else if(comment.substring(0,5)=="/perm") {
289				//運営コメント(perm)
290				var perm_array = comment.split(" ");
291				var perm = "";
292				for(var i=1; i<perm_array.length; i++) {
293					perm += perm_array[i]+ " ";
294				}
295				comment = perm;
296			} else if(comment.substring(0,1)=="/") {
297				//運営コメント
298				comment = comment.substr(1);
299			}
300			//<>を元に戻す
301			comment = comment.replace(/&amp;/g,"&");
302			comment = comment.replace(/&lt;/g,"<");
303			comment = comment.replace(/&gt;/g,">");
304			
305			//htmlタグ除去
306			var pattern = /<("[^"]*"|'[^']*'|[^'">])*>/g;
307			comment = comment.replace(pattern,'');
308			
309			return comment.trim();
310		}
311	}
312	</script>
313	</head>
314	
315	<body onload="init();">
316		<canvas id="canvas" width="512" height="300"></canvas>
317	</body>
318	</html>
